3	public actor UsagesFileManager {
4	    // Internal init so tests can create isolated instances via @testable import.
5	    // Production code must use `UsagesFileManager.shared`.
6	    public static let shared = UsagesFileManager()
7	
8	    nonisolated public let filePath: String
9	    private let logger: FileLogger
10	
11	    init(
12	        filePath: String? = nil,
13	        logger: FileLogger = Loggers.app
14	    ) {
15	        let home = FileManager.default.homeDirectoryForCurrentUser.path
16	        self.filePath = filePath ?? "\(home)/.cache/ai-usages-tracker/usages.json"
17	        self.logger = logger
18	
19	        let dir = (self.filePath as NSString).deletingLastPathComponent
20	        do {
21	            try FileManager.default.createDirectory(atPath: dir, withIntermediateDirectories: true, attributes: nil)
22	        } catch {
23	            logger.log(.error, "Failed to create directory \(dir): \(error)")
24	        }
25	    }
26	
27	    // MARK: - Public
28	
29	    public func read() -> UsagesFile {
30	        readUnsafe()
31	    }
32	
33	    public func update(with entries: [VendorUsageEntry]) {
34	        var file = readUnsafe()
35	        file = merge(existing: file, incoming: entries)
36	        writeUnsafe(file)
37	    }
38	
39	    // MARK: - Active-account update
40	
41	    public func updateIsActive(vendor: Vendor, activeAccount: AccountEmail?) {
42	        var file = readUnsafe()
43	        var changed = false
44	        for i in file.usages.indices {
45	            guard file.usages[i].vendor == vendor else { continue }
46	            let newActive = file.usages[i].account == activeAccount
47	            if file.usages[i].isActive != newActive {
48	                file.usages[i].isActive = newActive
49	                changed = true
50	            }
51	        }
52	        if changed {
53	            writeUnsafe(file)
54	        }
55	    }
56	
57	    // MARK: - Merge logic
58	
59	    public func merge(existing: UsagesFile, incoming: [VendorUsageEntry]) -> UsagesFile {
60	        var usages = existing.usages
61	        var indexByKey: [String: Int] = [:]
62	        for (i, entry) in usages.enumerated() {
63	            indexByKey["\(entry.vendor.rawValue)|\(entry.account.rawValue)"] = i
64	        }
65	        for entry in incoming {
66	            let key = "\(entry.vendor.rawValue)|\(entry.account.rawValue)"
67	            if let idx = indexByKey[key] {
68	                usages[idx] = entry
69	            } else {
70	                indexByKey[key] = usages.count
71	                usages.append(entry)
72	            }
